  1→/**
  2→ * Knowledge graph page: force-directed visualization of sessions and knowledge links.
  3→ * Inline vanilla JS, no CDN dependencies.
  4→ */
  5→
  6→import type { ManifestEntry } from '../../types/transcript.js'
  7→import type { LinkGraph } from '../../types/report.js'
  8→import type { Translations } from '../i18n/types.js'
  9→import type { MarkdownFile } from './layout.js'
 10→import { escHtml, htmlShell, renderNav, transcriptUrlFromRoot, slugifyName } from './layout.js'
 11→
 12→const MAX_NODES = 500
 13→
 14→// ---------------------------------------------------------------------------
 15→// Graph data types
 16→// ---------------------------------------------------------------------------
 17→
 18→interface GraphNode {
 19→  id: string
 20→  label: string
 21→  type: 'session' | 'knowledge'
 22→  client?: string
 23→  url: string
 24→}
 25→
 26→interface GraphEdge {
 27→  source: string
 28→  target: string
 29→}
 30→
 31→// ---------------------------------------------------------------------------
 32→// Build graph data
 33→// ---------------------------------------------------------------------------
 34→
 35→export function buildGraphData(
 36→  manifests: ManifestEntry[],
 37→  knowledgeFiles: MarkdownFile[],
 38→  linkGraph: LinkGraph,
 39→): { nodes: GraphNode[]; edges: GraphEdge[] } {
 40→  // Cap manifests to MAX_NODES (most recent first)
 41→  const sorted = [...manifests]
 42→    .sort((a, b) => b.started_at.localeCompare(a.started_at))
 43→    .slice(0, MAX_NODES)
 44→
 45→  const nodeSet = new Set<string>()
 46→  const nodes: GraphNode[] = []
 47→  const edges: GraphEdge[] = []
 48→
 49→  for (const m of sorted) {
 50→    if (!nodeSet.has(m.session_id)) {
 51→      nodeSet.add(m.session_id)
 52→      nodes.push({
 53→        id: m.session_id,
 54→        label: m.title || m.session_id.slice(0, 8),
 55→        type: 'session',
 56→        client: m.client,
 57→        url: transcriptUrlFromRoot(m),
 58→      })
 59→    }
 60→  }
 61→
 62→  for (const kf of knowledgeFiles) {
 63→    const id = `knowledge:${kf.filename}`
 64→    if (!nodeSet.has(id)) {
 65→      nodeSet.add(id)
 66→      nodes.push({
 67→        id,
 68→        label: kf.title || kf.filename,
 69→        type: 'knowledge',
 70→        url: `knowledge/index.html#${slugifyName(kf.filename)}`,
 71→      })
 72→    }
 73→  }
 74→
 75→  // Add edges from link graph (only for nodes that exist)
 76→  for (const [sourceId, targets] of Object.entries(linkGraph.forwardLinks)) {
 77→    if (!nodeSet.has(sourceId)) continue
 78→    for (const targetId of targets) {
 79→      if (nodeSet.has(targetId)) {
 80→        edges.push({ source: sourceId, target: targetId })
 81→      }
 82→    }
 83→  }
 84→
 85→  return { nodes, edges }
 86→}
 87→
 88→// ---------------------------------------------------------------------------
 89→// Graph page renderer
 90→
 91→export function renderGraph(
 92→  manifests: ManifestEntry[],
 93→  knowledgeFiles: MarkdownFile[],
 94→  linkGraph: LinkGraph,
 95→  t?: Translations,
 96→): string {
 97→  const nav = renderNav('graph', 0, t)
 98→  const title = t?.graph.title ?? 'Knowledge Graph'
 99→  const subtitle = t?.graph.subtitle ?? 'Connections between sessions and knowledge files'
100→
101→  const { nodes, edges } = buildGraphData(manifests, knowledgeFiles, linkGraph)
102→
103→  if (nodes.length === 0) {
104→    const content = `<div class="page-header">
105→  <h1>${escHtml(title)}</h1>
106→  <p class="subtitle">${escHtml(t?.graph.noData ?? 'No graph data available.')}</p>
107→</div>`
108→    return htmlShell(title, content, nav)
109→  }
110→
111→  // Embed graph data as JSON; escape sequences that could break a <script> block
112→  const graphDataJson = JSON.stringify({ nodes, edges })
113→    .replace(/<\//g, '<\\/')
114→    .replace(/\u2028/g, '\\u2028')
115→    .replace(/\u2029/g, '\\u2029')
116→
117→  const graphScript = `<script>
118→(function() {
119→var GRAPH_DATA = ${graphDataJson};
120→
121→// Client color map
122→var CLIENT_COLORS = { claude: '#bc8cff', codex: '#58a6ff', gemini: '#3fb950' };
123→function nodeColor(n) {
124→  if (n.type === 'knowledge') return '#f0c040';
125→  return CLIENT_COLORS[n.client] || '#8b949e';
126→}
127→function nodeRadius(n) { return n.type === 'knowledge' ? 7 : 5; }
128→
129→var canvas = document.getElementById('graph-canvas');
130→if (!canvas) return;
131→var ctx = canvas.getContext('2d');
132→
133→// High-DPI
134→function resize() {
135→  var rect = canvas.getBoundingClientRect();
136→  var dpr = window.devicePixelRatio || 1;
137→  canvas.width = rect.width * dpr;
138→  canvas.height = rect.height * dpr;
139→  ctx.scale(dpr, dpr);
140→}
141→resize();
142→window.addEventListener('resize', function() { resize(); draw(); });
143→
144→var W = canvas.getBoundingClientRect().width;
145→var H = canvas.getBoundingClientRect().height;
146→
147→// Init positions (random spread)
148→var nodeMap = {};
149→var simNodes = GRAPH_DATA.nodes.map(function(n) {
150→  var sn = { id: n.id, label: n.label, type: n.type, client: n.client, url: n.url,
151→    x: W/2 + (Math.random()-0.5)*W*0.7, y: H/2 + (Math.random()-0.5)*H*0.7, vx: 0, vy: 0 };
152→  nodeMap[n.id] = sn;
153→  return sn;
154→});
155→
156→var simEdges = GRAPH_DATA.edges.map(function(e) {
157→  return { source: nodeMap[e.source], target: nodeMap[e.target] };
158→}).filter(function(e) { return e.source && e.target; });
159→
160→// Simulation params — tuned for ~50–200 node graphs on a 900px canvas
161→var ALPHA = 1.0;        // initial energy; decays each tick
162→var ALPHA_DECAY = 0.0228; // decay rate ≈ ln(0.001)/300 (settles in ~300 ticks)
163→var ALPHA_MIN = 0.001;  // stop simulation below this threshold
164→var CHARGE = -120;      // repulsion strength between nodes (negative = push apart)
165→var LINK_DIST = 80;     // spring rest length in pixels
166→var CENTER_FORCE = 0.05; // gravity toward canvas center (prevents drift)
167→var DAMPING = 0.6;      // velocity damping per tick (higher = faster settling)
168→
169→// Pan/zoom state
170→var panX = 0, panY = 0, scale = 1;
171→var dragging = false, dragNode = null, dragOffX = 0, dragOffY = 0;
172→var isPanning = false, panStartX = 0, panStartY = 0, panStartPanX = 0, panStartPanY = 0;
173→
174→function worldToScreen(wx, wy) {
175→  return { x: (wx + panX) * scale + W/2, y: (wy + panY) * scale + H/2 };
176→}
177→function screenToWorld(sx, sy) {
178→  return { x: (sx - W/2) / scale - panX, y: (sy - H/2) / scale - panY };
179→}
180→
181→function tick() {
182→  if (ALPHA < ALPHA_MIN) return;
183→  ALPHA *= (1 - ALPHA_DECAY);
184→
185→  // Repulsion (n^2, capped)
186→  var N = simNodes.length;
187→  for (var i = 0; i < N; i++) {
188→    for (var j = i+1; j < N; j++) {
189→      var ni = simNodes[i], nj = simNodes[j];
190→      var dx = nj.x - ni.x, dy = nj.y - ni.y;
191→      var dist = Math.sqrt(dx*dx + dy*dy) || 1;
192→      var force = CHARGE / (dist * dist) * ALPHA;
193→      var fx = dx / dist * force, fy = dy / dist * force;
194→      ni.vx -= fx; ni.vy -= fy;
195→      nj.vx += fx; nj.vy += fy;
196→    }
197→  }
198→
199→  // Link attraction
200→  for (var k = 0; k < simEdges.length; k++) {
201→    var e = simEdges[k];
202→    var dx2 = e.target.x - e.source.x, dy2 = e.target.y - e.source.y;
203→    var dist2 = Math.sqrt(dx2*dx2 + dy2*dy2) || 1;
204→    var strength = (dist2 - LINK_DIST) / dist2 * 0.5 * ALPHA;
205→    var fx2 = dx2 * strength, fy2 = dy2 * strength;
206→    e.source.vx += fx2; e.source.vy += fy2;
207→    e.target.vx -= fx2; e.target.vy -= fy2;
208→  }
209→
210→  // Center gravity
211→  for (var m = 0; m < N; m++) {
212→    var node = simNodes[m];
213→    node.vx += -node.x * CENTER_FORCE * ALPHA;
214→    node.vy += -node.y * CENTER_FORCE * ALPHA;
215→    if (node === dragNode) continue;
216→    node.vx *= DAMPING;
217→    node.vy *= DAMPING;
218→    node.x += node.vx;
219→    node.y += node.vy;
220→  }
221→}
222→
223→function draw() {
224→  W = canvas.getBoundingClientRect().width;
225→  H = canvas.getBoundingClientRect().height;
226→  ctx.clearRect(0, 0, W, H);
227→  ctx.save();
228→
229→  // Draw edges
230→  ctx.strokeStyle = 'rgba(139,148,158,0.3)';
231→  ctx.lineWidth = 1;
232→  for (var k = 0; k < simEdges.length; k++) {
233→    var e = simEdges[k];
234→    var s = worldToScreen(e.source.x, e.source.y);
235→    var t2 = worldToScreen(e.target.x, e.target.y);
236→    ctx.beginPath();
237→    ctx.moveTo(s.x, s.y);
238→    ctx.lineTo(t2.x, t2.y);
239→    ctx.stroke();
240→  }
241→
242→  // Draw nodes
243→  for (var i = 0; i < simNodes.length; i++) {
244→    var n = simNodes[i];
245→    var pos = worldToScreen(n.x, n.y);
246→    var r = nodeRadius(n) * scale;
247→    ctx.beginPath();
248→    ctx.arc(pos.x, pos.y, Math.max(r, 3), 0, Math.PI*2);
249→    ctx.fillStyle = nodeColor(n);
250→    ctx.fill();
251→    if (n === hoverNode) {
252→      ctx.strokeStyle = '#fff';
253→      ctx.lineWidth = 1.5;
254→      ctx.stroke();
255→    }
256→  }
257→
258→  // Draw hover label
259→  if (hoverNode) {
260→    var hpos = worldToScreen(hoverNode.x, hoverNode.y);
261→    ctx.font = '11px sans-serif';
262→    ctx.fillStyle = '#e6edf3';
263→    ctx.fillText(hoverNode.label.slice(0, 30), hpos.x + 8, hpos.y - 4);
264→  }
265→
266→  ctx.restore();
267→}
268→
269→var hoverNode = null;
270→
271→function findNode(sx, sy) {
272→  var w = screenToWorld(sx, sy);
273→  var best = null, bestDist = Infinity;
274→  for (var i = 0; i < simNodes.length; i++) {
275→    var n = simNodes[i];
276→    var dx = n.x - w.x, dy = n.y - w.y;
277→    var dist = Math.sqrt(dx*dx + dy*dy);
278→    if (dist < 15 / scale && dist < bestDist) { best = n; bestDist = dist; }
279→  }
280→  return best;
281→}
282→
283→function getCanvasPos(evt) {
284→  var rect = canvas.getBoundingClientRect();
285→  return { x: evt.clientX - rect.left, y: evt.clientY - rect.top };
286→}
287→
288→canvas.addEventListener('mousemove', function(e) {
289→  var pos = getCanvasPos(e);
290→  if (isPanning) {
291→    panX = panStartPanX + (pos.x - panStartX) / scale;
292→    panY = panStartPanY + (pos.y - panStartY) / scale;
293→    return;
294→  }
295→  if (dragNode) {
296→    var w = screenToWorld(pos.x, pos.y);
297→    dragNode.x = w.x + dragOffX;
298→    dragNode.y = w.y + dragOffY;
299→    dragNode.vx = 0; dragNode.vy = 0;
300→    return;
301→  }
302→  var node = findNode(pos.x, pos.y);
303→  hoverNode = node;
304→  canvas.style.cursor = node ? 'pointer' : 'grab';
305→});
306→
307→canvas.addEventListener('mousedown', function(e) {
308→  var pos = getCanvasPos(e);
309→  var node = findNode(pos.x, pos.y);
310→  if (node) {
311→    dragNode = node;
312→    var w = screenToWorld(pos.x, pos.y);
313→    dragOffX = node.x - w.x;
314→    dragOffY = node.y - w.y;
315→    ALPHA = 0.3;
316→  } else {
317→    isPanning = true;
318→    panStartX = pos.x; panStartY = pos.y;
319→    panStartPanX = panX; panStartPanY = panY;
320→  }
321→});
322→
323→canvas.addEventListener('mouseup', function(e) {
324→  if (dragNode) { dragNode = null; return; }
325→  isPanning = false;
326→});
327→
328→canvas.addEventListener('click', function(e) {
329→  var pos = getCanvasPos(e);
330→  var node = findNode(pos.x, pos.y);
331→  if (node && node.url) { window.location.href = node.url; }
332→});
333→
334→canvas.addEventListener('wheel', function(e) {
335→  e.preventDefault();
336→  var pos = getCanvasPos(e);
337→  var factor = e.deltaY > 0 ? 0.9 : 1.1;
338→  var wx = (pos.x - W/2) / scale - panX;
339→  var wy = (pos.y - H/2) / scale - panY;
340→  scale *= factor;
341→  scale = Math.max(0.1, Math.min(10, scale));
342→  panX = (pos.x - W/2) / scale - wx;
343→  panY = (pos.y - H/2) / scale - wy;
344→}, { passive: false });
345→
346→// Animation loop — stops automatically once simulation settles
347→function loop() {
348→  tick();
349→  draw();
350→  if (ALPHA >= ALPHA_MIN) {
351→    requestAnimationFrame(loop);
352→  }
353→}
354→loop();
355→})();
356→</script>`
357→
358→  const legendItems = [
359→    { color: '#bc8cff', label: 'Claude' },
360→    { color: '#58a6ff', label: 'Codex' },
361→    { color: '#3fb950', label: 'Gemini' },
362→    { color: '#8b949e', label: 'Other' },
363→    { color: '#f0c040', label: 'Knowledge' },
364→  ]
365→
366→  const legend = legendItems.map(item =>
367→    `<div class="graph-legend-item">
368→  <span class="graph-legend-dot" style="background:${escHtml(item.color)}"></span>
369→  ${escHtml(item.label)}
370→</div>`
371→  ).join('')
372→
373→  const content = `<div class="page-header">
374→  <h1>${escHtml(title)}</h1>
375→  <p class="subtitle">${escHtml(subtitle)} · ${nodes.length} nodes, ${edges.length} edges</p>
376→</div>
377→<canvas id="graph-canvas"></canvas>
378→<div class="graph-legend">${legend}</div>`
379→
380→  return htmlShell(title, content, nav, graphScript)
381→}
