  1→/**
  2→ * Full-text search: pre-built JSON index embedded as inline JS.
  3→ * Vanilla JS substring search, no external library.
  4→ */
  5→
  6→import type { ManifestEntry } from '../../types/transcript.js'
  7→import type { SearchIndexEntry } from '../../types/report.js'
  8→import type { Translations } from '../i18n/types.js'
  9→import { escHtml, htmlShell, renderNav, transcriptUrlFromRoot } from './layout.js'
 10→
 11→const MAX_INDEX_BYTES = 50_000
 12→const SNIPPET_LEN = 200
 13→
 14→// ---------------------------------------------------------------------------
 15→// Index construction
 16→// ---------------------------------------------------------------------------
 17→
 18→export function buildSearchIndex(
 19→  manifests: ManifestEntry[],
 20→  getSnippet: (m: ManifestEntry) => string,
 21→): SearchIndexEntry[] {
 22→  const entries: SearchIndexEntry[] = []
 23→  let totalBytes = 0
 24→
 25→  for (const m of manifests) {
 26→    let snippet = getSnippet(m).slice(0, SNIPPET_LEN)
 27→    const project = m.project || lastPathSegment(m.cwd) || 'unknown'
 28→
 29→    // Check if truncating the snippet is needed to stay within budget
 30→    const baseBytes = JSON.stringify({
 31→      url: transcriptUrl(m),
 32→      title: m.title || m.session_id,
 33→      client: m.client,
 34→      project,
 35→      date: m.started_at.slice(0, 10),
 36→      snippet: '',
 37→    }).length
 38→    const budgetForSnippet = MAX_INDEX_BYTES - totalBytes - baseBytes - 10
 39→    if (budgetForSnippet < 20) break
 40→    if (baseBytes + snippet.length > MAX_INDEX_BYTES - totalBytes) {
 41→      snippet = snippet.slice(0, Math.max(0, budgetForSnippet))
 42→    }
 43→
 44→    const entry: SearchIndexEntry = {
 45→      url: transcriptUrl(m),
 46→      title: m.title || m.session_id,
 47→      client: m.client,
 48→      project,
 49→      date: m.started_at.slice(0, 10),
 50→      snippet,
 51→    }
 52→    totalBytes += JSON.stringify(entry).length
 53→    entries.push(entry)
 54→  }
 55→
 56→  return entries
 57→}
 58→
 59→function transcriptUrl(m: ManifestEntry): string {
 60→  return transcriptUrlFromRoot(m)
 61→}
 62→
 63→function lastPathSegment(p: string): string {
 64→  return p.split(/[/\\]/).filter(Boolean).at(-1) ?? ''
 65→}
 66→
 67→// ---------------------------------------------------------------------------
 68→// Search page renderer
 69→// ---------------------------------------------------------------------------
 70→
 71→export function renderSearchPage(index: SearchIndexEntry[], t?: Translations): string {
 72→  // Escape </script> to prevent script-injection via manifest-controlled content
 73→  const indexJson = JSON.stringify(index).replace(/<\//g, '<\\/')
 74→  const nav = renderNav('search', 0, t)
 75→  const title = t?.search.title ?? 'Search'
 76→  const placeholder = t?.search.placeholder ?? 'Search sessions, messages, and content...'
 77→
 78→  // Build unique client and project lists for filter dropdowns
 79→  const clients = [...new Set(index.map(e => e.client).filter(Boolean))].sort()
 80→  const projects = [...new Set(index.map(e => e.project).filter(Boolean))].sort()
 81→
 82→  const clientOptions = clients
 83→    .map(c => `<option value="${escHtml(c)}">${escHtml(c)}</option>`)
 84→    .join('')
 85→  const projectOptions = projects
 86→    .map(p => `<option value="${escHtml(p)}">${escHtml(p)}</option>`)
 87→    .join('')
 88→
 89→  const extraHead = `<script>
 90→const SEARCH_INDEX = ${indexJson};
 91→</script>`
 92→
 93→  const content = `
 94→<div class="page-header">
 95→  <h1>${escHtml(title)}</h1>
 96→  <p class="subtitle">Full-text search across all imported sessions</p>
 97→</div>
 98→
 99→<div style="display:flex;gap:0.5rem;margin-bottom:0.75rem;flex-wrap:wrap">
100→  <select id="filter-client" class="search-filter-select">
101→    <option value="">All Clients</option>
102→    ${clientOptions}
103→  </select>
104→  <select id="filter-project" class="search-filter-select">
105→    <option value="">All Projects</option>
106→    ${projectOptions}
107→  </select>
108→</div>
109→<input
110→  type="search"
111→  id="search-input"
112→  class="search-box"
113→  placeholder="${escHtml(placeholder)}"
114→  autofocus
115→>
116→<div id="search-count"></div>
117→<div id="search-results" class="search-results"></div>
118→
119→<script>
120→(function() {
121→  var input = document.getElementById('search-input');
122→  var resultsEl = document.getElementById('search-results');
123→  var countEl = document.getElementById('search-count');
124→  var clientSel = document.getElementById('filter-client');
125→  var projectSel = document.getElementById('filter-project');
126→
127→  function highlight(text, query) {
128→    if (!query) return escHtml(text);
129→    var escaped = escHtml(text);
130→    var escapedQ = escHtml(query);
131→    var lower = escaped.toLowerCase();
132→    var lowerQ = escapedQ.toLowerCase();
133→    if (!lowerQ) return escaped;
134→    var result = '';
135→    var i = 0;
136→    while (i < escaped.length) {
137→      var idx = lower.indexOf(lowerQ, i);
138→      if (idx === -1) { result += escaped.slice(i); break; }
139→      result += escaped.slice(i, idx) + '<mark>' + escaped.slice(idx, idx + lowerQ.length) + '</mark>';
140→      i = idx + lowerQ.length;
141→    }
142→    return result;
143→  }
144→
145→  function escHtml(s) {
146→    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
147→  }
148→
149→  function renderResults() {
150→    var query = (input.value || '');
151→    var q = query.toLowerCase().trim();
152→    var filterClient = clientSel ? clientSel.value : '';
153→    var filterProject = projectSel ? projectSel.value : '';
154→    var filtered = SEARCH_INDEX.filter(function(e) {
155→      if (filterClient && e.client !== filterClient) return false;
156→      if (filterProject && e.project !== filterProject) return false;
157→      if (!q) return true;
158→      return (e.title || '').toLowerCase().includes(q) ||
159→             (e.snippet || '').toLowerCase().includes(q);
160→    });
161→    if (!q && !filterClient && !filterProject) {
162→      resultsEl.innerHTML = '';
163→      countEl.textContent = SEARCH_INDEX.length + ' session(s) indexed';
164→      return;
165→    }
166→    countEl.textContent = filtered.length + ' result(s)' + (q ? ' for "' + escHtml(q) + '"' : '');
167→    resultsEl.innerHTML = filtered.map(function(e) {
168→      return '<div class="search-result">' +
169→        '<div class="search-result-title"><a href="' + escHtml(e.url) + '">' + highlight(e.title, query) + '</a></div>' +
170→        '<div class="search-result-meta"><span class="badge badge-' + escHtml(e.client) + '">' + escHtml(e.client) + '</span> &nbsp; ' + escHtml(e.date) + '</div>' +
171→        '<div class="search-result-snippet">' + highlight(e.snippet, query) + '</div>' +
172→        '</div>';
173→    }).join('');
174→  }
175→
176→  renderResults();
177→  input.addEventListener('input', renderResults);
178→  if (clientSel) clientSel.addEventListener('change', renderResults);
179→  if (projectSel) projectSel.addEventListener('change', renderResults);
180→})();
181→</script>`
182→
183→  return htmlShell(title, content, nav, extraHead)
184→}
