// Shared MarkdownFile type and slug helper
// ---------------------------------------------------------------------------

export interface MarkdownFile {
  filename: string
  title: string
  content: string
}

export function slugifyName(name: string): string {
  return name.toLowerCase().replace(/[^a-z0-9]+/g, '-')
}

// ---------------------------------------------------------------------------
// HTML shell
// ---------------------------------------------------------------------------

export interface HtmlShellOptions {
  extraHead?: string
  lang?: string
  breadcrumb?: string
  /** Inject reader-mode toggle button into the page */
  readerMode?: boolean
  /** Open Graph description (og:description). Truncated to 200 chars. */
  ogDescription?: string
  /** Absolute URL for og:url. Omitted when empty. */
  ogUrl?: string
}

export function htmlShell(
  title: string,
  content: string,
  nav: string,
  extraHeadOrOpts: string | HtmlShellOptions = '',
  lang = 'en',
): string {
  // Accept legacy string arg (extraHead) or new options object
  const opts: HtmlShellOptions = typeof extraHeadOrOpts === 'string'
    ? { extraHead: extraHeadOrOpts, lang }
    : extraHeadOrOpts
  const extraHead = opts.extraHead ?? ''
  const resolvedLang = opts.lang ?? lang
  const breadcrumb = opts.breadcrumb ?? ''
  const readerBtn = opts.readerMode !== false
    ? `<button class="reader-toggle-btn" id="reader-toggle" type="button" title="Toggle reader mode">📖</button>`
    : ''

  // Open Graph meta tags
  const ogDesc = opts.ogDescription ? opts.ogDescription.slice(0, 200) : ''
  const ogMeta = [
    `<meta property="og:title" content="${escHtml(title)}">`,
    `<meta property="og:type" content="website">`,
    ogDesc ? `<meta property="og:description" content="${escHtml(ogDesc)}">` : '',
    opts.ogUrl ? `<meta property="og:url" content="${escHtml(opts.ogUrl)}">` : '',
  ].filter(Boolean).join('\n')

  const topbar = `<header class="topbar" id="topbar">
  <span class="topbar-brand">MemoryTree</span>
  <div class="topbar-actions">
    <button class="theme-toggle-btn" id="theme-toggle-mobile" type="button">☀</button>
    <button class="hamburger" id="hamburger" type="button">☰</button>
  </div>
</header>`

  return `<!DOCTYPE html>
<html lang="${escHtml(resolvedLang)}" data-theme="dark">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>${escHtml(title)} — MemoryTree</title>
${ogMeta}
<style>${REPORT_CSS}</style>
${extraHead}
${SIDEBAR_INLINE_JS}
</head>
<body>
${topbar}
${nav}
<div class="main-content">
  <div class="container">
${breadcrumb ? `${breadcrumb}\n` : ''}<div style="display:flex;justify-content:flex-end;margin-bottom:0.5rem">${readerBtn}</div>
${content}
  </div>
</div>
</body>
</html>`
}

/**
 * Link graph construction: detects [[session_id]] / [[stem]] references
 * in clean markdown content and builds forward/backlink maps.
 */

import { existsSync, readFileSync } from 'node:fs'
import { basename, join } from 'node:path'

import type { ManifestEntry } from '@openmnemo/types'
import type { LinkGraph } from '../types.js'

// ---------------------------------------------------------------------------
// Link graph builder
// ---------------------------------------------------------------------------

export function buildLinkGraph(manifests: ManifestEntry[], root: string): LinkGraph {
  const forwardLinks: Record<string, string[]> = {}
  const backlinks: Record<string, string[]> = {}

  // Build lookup table: various identifiers → canonical session_id
  const lookup: Record<string, string> = {}
  for (const m of manifests) {
    // Register by session_id
    lookup[m.session_id] = m.session_id
    // Register by artifact stem (e.g. "019cf4b1-....__0ebaa458")
    const cleanPath = m.repo_clean_path || m.global_clean_path
    if (cleanPath) {
      const stem = basename(cleanPath, '.md')
      if (stem) lookup[stem] = m.session_id
    }
  }

  for (const m of manifests) {
    const cleanPath = resolveCleanPath(m, root)
    if (!cleanPath || !existsSync(cleanPath)) continue

    let content: string
    try {
      content = readFileSync(cleanPath, 'utf-8')
    } catch {
      continue
    }

    const refs = extractLinks(content)
    for (const ref of refs) {
      const targetId = lookup[ref]
      if (!targetId || targetId === m.session_id) continue // skip self-refs

      // Forward: m → target (immutable update)
      const fwd = forwardLinks[m.session_id] ?? []
      if (!fwd.includes(targetId)) {
        forwardLinks[m.session_id] = [...fwd, targetId]
      }

      // Backlink: target ← m (immutable update)
      const back = backlinks[targetId] ?? []
      if (!back.includes(m.session_id)) {
        backlinks[targetId] = [...back, m.session_id]
      }
    }
  }

  return { backlinks, forwardLinks }
}

// ---------------------------------------------------------------------------
// Link extraction
// ---------------------------------------------------------------------------

/** Extract all [[...]] references from text. */
export function extractLinks(content: string): string[] {
  const results: string[] = []
  const re = /\[\[([^\][\n]+)\]\]/g
  let match: RegExpExecArray | null
  while ((match = re.exec(content)) !== null) {
    const ref = match[1]?.trim()
    if (ref && ref.length > 0) {
      results.push(ref)
    }
  }
  return results
}

// ---------------------------------------------------------------------------
// Path helpers
// ---------------------------------------------------------------------------

export function resolveCleanPath(m: ManifestEntry, root: string): string | null {
  if (m.repo_clean_path) {
    return join(root, m.repo_clean_path)
  }
  if (m.global_clean_path) {
    return m.global_clean_path
  }
  return null
}

/**
 * Minimal Markdown → HTML converter.
 * Handles: headings, bold, italic, inline code, fenced code blocks,
 *          lists, blockquotes, callouts (> [!type]), mermaid diagrams.
 * All content is HTML-escaped before applying structural tags.
 */

import { escHtml } from './layout.js'

// ---------------------------------------------------------------------------
// Callout configuration
// ---------------------------------------------------------------------------

const CALLOUT_ICONS: Record<string, string> = {
  note:      '📝',
  tip:       '💡',
  important: '❗',
  warning:   '⚠️',
  caution:   '🔥',
  info:      'ℹ️',
  success:   '✅',
  error:     '❌',
}

// ---------------------------------------------------------------------------
// Mermaid detection (separate from conversion)
// ---------------------------------------------------------------------------

/** Returns true if the markdown source contains at least one ```mermaid block. */
export function hasMermaidBlocks(md: string): boolean {
  return /^```mermaid\s*$/m.test(md)
}

/**
 * CDN script tag to inject on pages containing mermaid diagrams.
 * Pinned to mermaid@11 via jsDelivr with SRI integrity hash.
 */
export const MERMAID_CDN_SCRIPT = `<script type="module">
import mermaid from 'https://cdn.jsdelivr.net/npm/mermaid@11/dist/mermaid.esm.min.mjs';
mermaid.initialize({ startOnLoad: true, theme: document.documentElement.getAttribute('data-theme') === 'light' ? 'default' : 'dark' });
</script>`

// ---------------------------------------------------------------------------
// Main converter
// ---------------------------------------------------------------------------

export function markdownToHtml(md: string): string {
  const lines = md.split('\n')
  const output: string[] = []
  let i = 0
  let inList = false
  let listType: 'ul' | 'ol' | null = null

  function closeList() {
    if (inList) {
      output.push(listType === 'ol' ? '</ol>' : '</ul>')
      inList = false
      listType = null
    }
  }

  while (i < lines.length) {
    const line = lines[i] ?? ''

    // Fenced code block (including mermaid)
    if (line.startsWith('```')) {
      closeList()
      const lang = line.slice(3).trim()
      const codeLines: string[] = []
      i++
      while (i < lines.length && !(lines[i] ?? '').startsWith('```')) {
        codeLines.push(lines[i] ?? '')
        i++
      }
      const codeContent = codeLines.join('\n')
      if (lang === 'mermaid') {
        // Mermaid: render as <pre class="mermaid"> — processed client-side by mermaid.js
        output.push(`<pre class="mermaid">${escHtml(codeContent)}</pre>`)
      } else {
        output.push(`<pre><code${lang ? ` class="language-${escHtml(lang)}"` : ''}>${escHtml(codeContent)}</code></pre>`)
      }
      i++
      continue
    }

    // YAML front matter (skip)
    if (i === 0 && line === '---') {
      i++
      while (i < lines.length && (lines[i] ?? '') !== '---') i++
      i++ // skip closing ---
      continue
    }

    // Headings
    const headingMatch = line.match(/^(#{1,6})\s+(.*)$/)
    if (headingMatch) {
      closeList()
      const level = headingMatch[1]?.length ?? 1
      const text = headingMatch[2] ?? ''
      output.push(`<h${level}>${applyInline(text)}</h${level}>`)
      i++
      continue
    }

    // Horizontal rule
    if (/^---+$/.test(line.trim())) {
      closeList()
      output.push('<hr>')
      i++
      continue
    }

    // Ordered list
    const olMatch = line.match(/^(\s*)\d+\.\s+(.+)$/)
    if (olMatch) {
      if (!inList || listType !== 'ol') {
        closeList()
        output.push('<ol>')
        inList = true
        listType = 'ol'
      }
      output.push(`<li>${applyInline(olMatch[2] ?? '')}</li>`)
      i++
      continue
    }

    // Unordered list
    const ulMatch = line.match(/^(\s*)[-*+]\s+(.+)$/)
    if (ulMatch) {
      if (!inList || listType !== 'ul') {
        closeList()
        output.push('<ul>')
        inList = true
        listType = 'ul'
      }
      output.push(`<li>${applyInline(ulMatch[2] ?? '')}</li>`)
      i++
      continue
    }

    // Blockquote / Callout
    if (line.startsWith('> ') || line === '>') {
      closeList()
      const bqLines: string[] = []
      while (i < lines.length && ((lines[i] ?? '').startsWith('> ') || (lines[i] ?? '') === '>')) {
        bqLines.push((lines[i] ?? '').replace(/^> ?/, ''))
        i++
      }
      output.push(renderBlockquote(bqLines))
      continue
    }

    // Blank line
    if (!line.trim()) {
      closeList()
      i++
      continue
    }

    // Paragraph
    closeList()
    output.push(`<p>${applyInline(line)}</p>`)
    i++
  }

  closeList()
  return output.join('\n')
}

// ---------------------------------------------------------------------------
// Blockquote / Callout renderer
// ---------------------------------------------------------------------------

function renderBlockquote(innerLines: string[]): string {
  const firstLine = innerLines[0] ?? ''
  const calloutMatch = firstLine.match(/^\[!(note|tip|important|warning|caution|info|success|error)\]$/i)

  if (calloutMatch) {
    const type = calloutMatch[1]!.toLowerCase()
    const icon = CALLOUT_ICONS[type] ?? '💬'
    const title = type.charAt(0).toUpperCase() + type.slice(1)
    const bodyLines = innerLines.slice(1).filter(l => l !== '')
    const body = bodyLines.map(l => `<p>${applyInline(l)}</p>`).join('\n')
    return `<div class="callout callout-${escHtml(type)}">
  <div class="callout-title">${icon} ${escHtml(title)}</div>
  <div class="callout-body">${body}</div>
</div>`
  }

  // Regular blockquote
  const inner = innerLines.map(l => `<p>${applyInline(l)}</p>`).join('\n')
  return `<blockquote>${inner}</blockquote>`
}

// ---------------------------------------------------------------------------
// Inline formatting
// ---------------------------------------------------------------------------

function applyInline(text: string): string {
  // Process links before HTML-escaping to avoid double-escaping href/label
  const withLinks = text.replace(/\[([^\]]+)\]\(([^)]+)\)/g, (_, label: string, href: string) => {
    return `<a href="${escHtml(href)}" target="_blank" rel="noopener">${escHtml(label)}</a>`
  })
  // Escape remaining text, then apply inline patterns on already-safe content
  // Split on the <a> tags we just inserted so they are not re-escaped
  const parts = withLinks.split(/(<a [^>]+>.*?<\/a>)/g)
  const processed = parts
    .map((part, i) => {
      if (i % 2 === 1) return part // already-generated <a> tag, pass through
      const escaped = escHtml(part)
      return escaped
        .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
        .replace(/\*(.+?)\*/g, '<em>$1</em>')
        .replace(/__(.+?)__/g, '<strong>$1</strong>')
        .replace(/_(.+?)_/g, '<em>$1</em>')
        .replace(/`([^`]+)`/g, '<code>$1</code>')
    })
    .join('')
  return processed
}

/**
 * Projects page: groups sessions by their working directory (last segment).
 */

import type { ManifestEntry } from '@openmnemo/types'
import type { Translations } from '../i18n/types.js'
import { clientBadge, escHtml, htmlShell, renderNav } from './layout.js'

// ---------------------------------------------------------------------------
// Project extraction
// ---------------------------------------------------------------------------

export function extractProject(cwd: string): string {
  if (!cwd) return 'unknown'
  return cwd.split(/[/\\]/).filter(Boolean).at(-1) ?? 'unknown'
}

// ---------------------------------------------------------------------------
// Projects page
// ---------------------------------------------------------------------------

export function renderProjects(manifests: ManifestEntry[], t?: Translations): string {
  const nav = renderNav('projects', 1, t)
  const title = t?.projects.title ?? 'Projects'

  if (manifests.length === 0) {
    const content = `<div class="page-header">
  <h1>${escHtml(title)}</h1>
  <p class="subtitle">${escHtml(t?.projects.noProjects ?? 'No projects found.')}</p>
</div>`
    return htmlShell(title, content, nav)
  }

  // Group by project name
  const projectMap = new Map<string, ManifestEntry[]>()
  for (const m of manifests) {
    const proj = extractProject(m.cwd)
    const group = projectMap.get(proj)
    if (group) {
      group.push(m)
    } else {
      projectMap.set(proj, [m])
    }
  }

  // Sort by session count desc
  const sorted = [...projectMap.entries()].sort((a, b) => b[1].length - a[1].length)

  const sessionLabel = t?.projects.sessions ?? 'sessions'

  const cards = sorted.map(([name, sessions]) => {
    const count = sessions.length
    const lastActive = sessions
      .map(s => s.started_at)
      .sort()
      .at(-1)
      ?.slice(0, 10) ?? '—'

    const clients = [...new Set(sessions.map(s => s.client))]
    const badges = clients.map(c => clientBadge(c)).join(' ')

    return `<div class="project-card">
  <div class="project-card-name">${escHtml(name)}</div>
  <div class="project-card-meta">
    ${count} ${escHtml(sessionLabel)} · last active ${escHtml(lastActive)}
  </div>
  <div class="project-card-clients">${badges}</div>
</div>`
  }).join('\n')

  const content = `<div class="page-header">
  <h1>${escHtml(title)}</h1>
  <p class="subtitle">${sorted.length} project(s)</p>
</div>
<div class="project-grid">
${cards}
</div>`

  return htmlShell(title, content, nav)
}

/**
 * RSS 2.0 feed generator for MemoryTree sessions.
 * Generates a valid feed.xml file.
 * When baseUrl is empty, item links are omitted gracefully.
 */

import type { ManifestEntry } from '@openmnemo/types'
import { transcriptUrlFromRoot } from './layout.js'

// ---------------------------------------------------------------------------
// XML escaping
// ---------------------------------------------------------------------------

function xmlEsc(text: string): string {
  return text
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&apos;')
}

// ---------------------------------------------------------------------------
// RSS renderer
// ---------------------------------------------------------------------------

/**
 * Generate an RSS 2.0 feed from session manifests.
 *
 * @param manifests  All session manifests (sorted by started_at descending by caller)
 * @param summaries  Map of session_id → AI summary text
 * @param baseUrl    Absolute base URL (e.g. 'https://memory.example.com').
 *                   When empty, item <link> and channel <link> are omitted.
 */
export function renderRssFeed(
  manifests: ManifestEntry[],
  summaries: Record<string, string>,
  baseUrl: string,
): string {
  const MAX_ITEMS = 100
  const sorted = [...manifests]
    .sort((a, b) => b.started_at.localeCompare(a.started_at))
    .slice(0, MAX_ITEMS)

  const channelLink = baseUrl ? `\n  <link>${xmlEsc(baseUrl)}</link>` : ''

  const items = sorted.map(m => {
    const title = m.title || m.session_id
    const summary = summaries[m.session_id] ?? ''
    const pubDate = toRfc2822(m.started_at)
    const relUrl = transcriptUrlFromRoot(m)
    const absUrl = baseUrl ? `${baseUrl.replace(/\/$/, '')}/${relUrl}` : ''
    const linkTag = absUrl ? `\n    <link>${xmlEsc(absUrl)}</link>` : ''
    const guidTag = absUrl
      ? `\n    <guid isPermaLink="true">${xmlEsc(absUrl)}</guid>`
      : `\n    <guid isPermaLink="false">${xmlEsc(m.session_id)}</guid>`
    const descTag = summary
      ? `\n    <description>${xmlEsc(summary.slice(0, 500))}</description>`
      : ''
    return `  <item>
    <title>${xmlEsc(title)}</title>${linkTag}${guidTag}
    <pubDate>${xmlEsc(pubDate)}</pubDate>${descTag}
  </item>`
  }).join('\n')

  return `<?xml version="1.0" encoding="UTF-8"?>
<rss version="2.0" xmlns:atom="http://www.w3.org/2005/Atom">
<channel>
  <title>MemoryTree Sessions</title>${channelLink}
  <description>AI session transcripts exported by MemoryTree</description>
  <generator>MemoryTree</generator>
${items}
</channel>
</rss>`
}

// ---------------------------------------------------------------------------
// Helpers
// ---------------------------------------------------------------------------

/** Convert ISO 8601 to RFC 2822 format (required by RSS spec). */
function toRfc2822(iso: string): string {
  const d = new Date(iso)
  return isNaN(d.getTime()) ? new Date().toUTCString() : d.toUTCString()
}

/**
 * Full-text search: pre-built JSON index embedded as inline JS.
 * Vanilla JS substring search, no external library.
 */

import type { ManifestEntry } from '@openmnemo/types'
import type { SearchIndexEntry } from '../types.js'
import type { Translations } from '../i18n/types.js'
import { escHtml, htmlShell, renderNav, transcriptUrlFromRoot } from './layout.js'

const MAX_INDEX_BYTES = 50_000
const SNIPPET_LEN = 200

// ---------------------------------------------------------------------------
// Index construction
// ---------------------------------------------------------------------------

export function buildSearchIndex(
  manifests: ManifestEntry[],
  getSnippet: (m: ManifestEntry) => string,
): SearchIndexEntry[] {
  const entries: SearchIndexEntry[] = []
  let totalBytes = 0

  for (const m of manifests) {
    let snippet = getSnippet(m).slice(0, SNIPPET_LEN)
    const project = m.project || lastPathSegment(m.cwd) || 'unknown'

    // Check if truncating the snippet is needed to stay within budget
    const baseBytes = JSON.stringify({
      url: transcriptUrl(m),
      title: m.title || m.session_id,
      client: m.client,
      project,
      date: m.started_at.slice(0, 10),
      snippet: '',
    }).length
    const budgetForSnippet = MAX_INDEX_BYTES - totalBytes - baseBytes - 10
    if (budgetForSnippet < 20) break
    if (baseBytes + snippet.length > MAX_INDEX_BYTES - totalBytes) {
      snippet = snippet.slice(0, Math.max(0, budgetForSnippet))
    }

    const entry: SearchIndexEntry = {
      url: transcriptUrl(m),
      title: m.title || m.session_id,
      client: m.client,
      project,
      date: m.started_at.slice(0, 10),
      snippet,
    }
    totalBytes += JSON.stringify(entry).length
    entries.push(entry)
  }

  return entries
}

function transcriptUrl(m: ManifestEntry): string {
  return transcriptUrlFromRoot(m)
}

function lastPathSegment(p: string): string {
  return p.split(/[/\\]/).filter(Boolean).at(-1) ?? ''
}

// ---------------------------------------------------------------------------
// Search page renderer
// ---------------------------------------------------------------------------

export function renderSearchPage(index: SearchIndexEntry[], t?: Translations): string {
  // Escape </script> to prevent script-injection via manifest-controlled content
  const indexJson = JSON.stringify(index).replace(/<\//g, '<\\/')
  const nav = renderNav('search', 0, t)
  const title = t?.search.title ?? 'Search'
  const placeholder = t?.search.placeholder ?? 'Search sessions, messages, and content...'

  // Build unique client and project lists for filter dropdowns
  const clients = [...new Set(index.map(e => e.client).filter(Boolean))].sort()
  const projects = [...new Set(index.map(e => e.project).filter(Boolean))].sort()

  const clientOptions = clients
    .map(c => `<option value="${escHtml(c)}">${escHtml(c)}</option>`)
    .join('')
  const projectOptions = projects
    .map(p => `<option value="${escHtml(p)}">${escHtml(p)}</option>`)
    .join('')

  const extraHead = `<script>
const SEARCH_INDEX = ${indexJson};
</script>`

  const content = `
<div class="page-header">
  <h1>${escHtml(title)}</h1>
  <p class="subtitle">Full-text search across all imported sessions</p>
</div>

<div style="display:flex;gap:0.5rem;margin-bottom:0.75rem;flex-wrap:wrap">
  <select id="filter-client" class="search-filter-select">
    <option value="">All Clients</option>
    ${clientOptions}
  </select>
  <select id="filter-project" class="search-filter-select">
    <option value="">All Projects</option>
    ${projectOptions}
  </select>
</div>
<input
  type="search"
  id="search-input"
  class="search-box"
  placeholder="${escHtml(placeholder)}"
  autofocus
>
<div id="search-count"></div>
<div id="search-results" class="search-results"></div>

<script>
(function() {
  var input = document.getElementById('search-input');
  var resultsEl = document.getElementById('search-results');
  var countEl = document.getElementById('search-count');
  var clientSel = document.getElementById('filter-client');
  var projectSel = document.getElementById('filter-project');

  function highlight(text, query) {
    if (!query) return escHtml(text);
    var escaped = escHtml(text);
    var escapedQ = escHtml(query);
    var lower = escaped.toLowerCase();
    var lowerQ = escapedQ.toLowerCase();
    if (!lowerQ) return escaped;
    var result = '';
    var i = 0;
    while (i < escaped.length) {
      var idx = lower.indexOf(lowerQ, i);
      if (idx === -1) { result += escaped.slice(i); break; }
      result += escaped.slice(i, idx) + '<mark>' + escaped.slice(idx, idx + lowerQ.length) + '</mark>';
      i = idx + lowerQ.length;
    }
    return result;
  }

  function escHtml(s) {
    return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
  }

  function renderResults() {
    var query = (input.value || '');
    var q = query.toLowerCase().trim();
    var filterClient = clientSel ? clientSel.value : '';
    var filterProject = projectSel ? projectSel.value : '';
    var filtered = SEARCH_INDEX.filter(function(e) {
      if (filterClient && e.client !== filterClient) return false;
      if (filterProject && e.project !== filterProject) return false;
      if (!q) return true;
      return (e.title || '').toLowerCase().includes(q) ||
             (e.snippet || '').toLowerCase().includes(q);
    });
    if (!q && !filterClient && !filterProject) {
      resultsEl.innerHTML = '';
      countEl.textContent = SEARCH_INDEX.length + ' session(s) indexed';
      return;
    }
    countEl.textContent = filtered.length + ' result(s)' + (q ? ' for "' + escHtml(q) + '"' : '');
    resultsEl.innerHTML = filtered.map(function(e) {
      return '<div class="search-result">' +
        '<div class="search-result-title"><a href="' + escHtml(e.url) + '">' + highlight(e.title, query) + '</a></div>' +
        '<div class="search-result-meta"><span class="badge badge-' + escHtml(e.client) + '">' + escHtml(e.client) + '</span> &nbsp; ' + escHtml(e.date) + '</div>' +
        '<div class="search-result-snippet">' + highlight(e.snippet, query) + '</div>' +
        '</div>';
    }).join('');
  }

  renderResults();
  input.addEventListener('input', renderResults);
  if (clientSel) clientSel.addEventListener('change', renderResults);
  if (projectSel) projectSel.addEventListener('change', renderResults);
})();
</script>`

  return htmlShell(title, content, nav, extraHead)
}

/**
 * Table of contents extraction and rendering.
 * Extracts h2/h3 headings from raw markdown and generates a sticky TOC nav.
 */

import { escHtml } from './layout.js'

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface TocEntry {
  level: 2 | 3
  text: string
  /** URL-safe anchor id, duplicate-free (suffixed -1, -2, …) */
  id: string
}

// ---------------------------------------------------------------------------
// Extract TOC from raw markdown
// ---------------------------------------------------------------------------

/**
 * Parse h2 and h3 headings from markdown source.
 * Duplicate heading text gets a numeric suffix: `-1`, `-2`, …
 */
export function extractToc(md: string): TocEntry[] {
  const entries: TocEntry[] = []
  const seen = new Map<string, number>()

  for (const line of md.split('\n')) {
    const h2 = line.match(/^## (.+)$/)
    const h3 = line.match(/^### (.+)$/)
    const match = h2 ?? h3
    if (!match) continue

    const level: 2 | 3 = h2 ? 2 : 3
    const text = (match[1] ?? '').trim()
    const base = slugifyHeading(text)

    const count = seen.get(base) ?? 0
    const id = count === 0 ? base : `${base}-${count}`
    seen.set(base, count + 1)

    entries.push({ level, text, id })
  }

  return entries
}

// ---------------------------------------------------------------------------
// Render TOC HTML
// ---------------------------------------------------------------------------

/**
 * Render a collapsible TOC nav from extracted entries.
 * Returns empty string when entries is empty.
 */
export function renderToc(entries: TocEntry[]): string {
  if (entries.length === 0) return ''

  const items = entries
    .map(e => {
      const indent = e.level === 3 ? ' style="padding-left:1.25rem"' : ''
      return `<li${indent}><a href="#${escHtml(e.id)}">${escHtml(e.text)}</a></li>`
    })
    .join('\n      ')

  return `<nav class="toc" id="toc">
  <button class="toc-toggle" id="toc-toggle" type="button" aria-expanded="true">
    Contents <span class="toc-arrow">▾</span>
  </button>
  <ul class="toc-list" id="toc-list">
    ${items}
  </ul>
</nav>`
}

// ---------------------------------------------------------------------------
// TOC ID scoping
// ---------------------------------------------------------------------------

export function prefixTocIds(entries: TocEntry[], prefix: string): TocEntry[] {
  if (!prefix) return entries
  return entries.map(entry => ({
    ...entry,
    id: `${prefix}-${entry.id}`,
  }))
}

// ---------------------------------------------------------------------------
// Heading anchor injection
// ---------------------------------------------------------------------------

/**
 * Post-process rendered HTML to add id attributes to heading tags so
 * TOC anchor links resolve correctly.
 * Only modifies <h2> and <h3> tags without existing id attributes.
 */
export function injectHeadingIds(html: string, entries: TocEntry[]): string {
  if (entries.length === 0) return html

  // Process entries in order so duplicates match correctly
  const remaining = [...entries]
  // [\s\S]*? allows inline HTML inside headings (e.g. <strong>, <code>)
  return html.replace(/<h([23])>([\s\S]*?)<\/h[23]>/g, (full, levelStr, innerHtml) => {
    const level = parseInt(levelStr, 10) as 2 | 3
    // Strip HTML tags from rendered inner content to get plain text for matching
    const innerText = (innerHtml as string).replace(/<[^>]+>/g, '').trim()
    const idx = remaining.findIndex(e => {
      if (e.level !== level) return false
      // Compare plain text: strip markdown markers from entry text, strip HTML from inner
      return stripInlineMarkdown(e.text) === innerText || escHtml(e.text) === (innerHtml as string).trim()
    })
    if (idx === -1) return full
    const entry = remaining.splice(idx, 1)[0]!
    return `<h${level} id="${escHtml(entry.id)}">${innerHtml}</h${level}>`
  })
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function slugifyHeading(text: string): string {
  return text
    .toLowerCase()
    .replace(/[^\w\s-]/g, '')   // remove non-word chars except hyphen
    .trim()
    .replace(/[\s_]+/g, '-')   // spaces/underscores → hyphen
    .replace(/-+/g, '-')       // collapse multiple hyphens
}

/**
 * Strip common markdown inline markers to get plain text.
 * Used to match TOC entries against rendered HTML heading content.
 */
function stripInlineMarkdown(text: string): string {
  return text
    .replace(/\*\*([^*]+)\*\*/g, '$1')          // **bold**
    .replace(/\*([^*]+)\*/g, '$1')               // *italic*
    .replace(/`([^`]+)`/g, '$1')                 // `code`
    .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')    // [link](url) → text
    .trim()
}

/**
 * Todos page: renders markdown files from Memory/02_todos/.
 */

import type { Translations } from '../i18n/types.js'
import { escHtml, htmlShell, renderNav, slugifyName } from './layout.js'
import type { MarkdownFile } from './layout.js'
import { hasMermaidBlocks, markdownToHtml, MERMAID_CDN_SCRIPT } from './markdown.js'
import { extractToc, renderToc, injectHeadingIds, prefixTocIds } from './toc.js'

export type TodoFile = MarkdownFile

export function renderTodos(files: TodoFile[], t?: Translations): string {
  const nav = renderNav('todos', 1, t)
  const title = t?.nav.todos ?? 'Todos'

  if (files.length === 0) {
    const content = `<div class="page-header">
  <h1>${escHtml(title)}</h1>
  <p class="subtitle">No todo files found in Memory/02_todos/.</p>
</div>`
    return htmlShell(title, content, nav)
  }

  const sections = files
    .map(f => {
      const sectionId = slugifyName(f.filename)
      const tocEntries = prefixTocIds(extractToc(f.content), sectionId)
      const rawHtml = markdownToHtml(f.content)
      const htmlContent = injectHeadingIds(rawHtml, tocEntries)
      const toc = renderToc(tocEntries)
      return `<div class="card" id="${escHtml(sectionId)}">
  <h2>${escHtml(f.title)}</h2>
  <p style="font-size:0.8rem;color:var(--text-muted);margin-bottom:1rem">${escHtml(f.filename)}</p>
  ${toc}
  <div class="markdown-body">${htmlContent}</div>
</div>`
    })
    .join('\n')

  const content = `<div class="page-header">
  <h1>${escHtml(title)}</h1>
  <p class="subtitle">${files.length} todo file(s)</p>
</div>
${sections}`

  const hasMermaid = files.some(f => hasMermaidBlocks(f.content))
  return htmlShell(title, content, nav, hasMermaid ? { extraHead: MERMAID_CDN_SCRIPT } : {})
}

/**
 * Individual transcript page: metadata, AI summary, backlinks, messages.
 */

import type { ManifestEntry } from '@openmnemo/types'
import type { Translations } from '../i18n/types.js'
import { clientBadge, escHtml, htmlShell, renderNav, transcriptUrlFromRoot, transcriptUrlFromTranscript } from './layout.js'

// ---------------------------------------------------------------------------
// Parsed message for rendering
// ---------------------------------------------------------------------------

export interface RenderedMessage {
  role: string
  timestamp: string
  text: string
}

// ---------------------------------------------------------------------------
// Transcript page
// ---------------------------------------------------------------------------

export function renderTranscript(
  messages: RenderedMessage[],
  manifest: ManifestEntry,
  summary: string,
  backlinks: ManifestEntry[],
  t?: Translations,
  reportBaseUrl = '',
): string {
  const nav = renderNav('transcripts', 2, t)

  const content = [
    renderHeader(manifest, t),
    summary ? renderSummaryCard(summary, t) : '',
    backlinks.length > 0 ? renderBacklinks(backlinks, t) : '',
    renderMessages(messages, t),
  ]
    .filter(Boolean)
    .join('\n')

  const title = manifest.title || manifest.session_id
  const ogUrl = reportBaseUrl
    ? `${reportBaseUrl.replace(/\/$/, '')}/${transcriptUrlFromRoot(manifest)}`
    : ''
  const shellOptions = {
    ...(summary ? { ogDescription: summary } : {}),
    ...(ogUrl ? { ogUrl } : {}),
  }
  return htmlShell(title, content, nav, shellOptions)
}

// ---------------------------------------------------------------------------
// Sub-renderers
// ---------------------------------------------------------------------------

function renderHeader(m: ManifestEntry, t?: Translations): string {
  const badge = clientBadge(m.client)
  const date = m.started_at.slice(0, 10)
  const time = m.started_at.slice(11, 19)
  const clientLabel = t?.transcript.client ?? 'Client'
  const sessionIdLabel = t?.transcript.sessionId ?? 'Session ID'
  const msgsLabel = t?.transcript.messages ?? 'Messages'
  const toolEventsLabel = t?.transcript.toolEvents ?? 'Tool Events'
  const branchLabel = t?.transcript.branch ?? 'Branch'
  const cwdLabel = t?.transcript.workingDir ?? 'Working Dir'
  const shaLabel = t?.transcript.sha256 ?? 'SHA-256'

  return `<div class="page-header">
  <h1>${escHtml(m.title || m.session_id)}</h1>
</div>
<table class="meta-table card">
<tbody>
  <tr><td>${escHtml(clientLabel)}</td><td>${badge}</td></tr>
  <tr><td>Date</td><td>${escHtml(date)} ${escHtml(time)}</td></tr>
  <tr><td>${escHtml(sessionIdLabel)}</td><td><code>${escHtml(m.session_id)}</code></td></tr>
  <tr><td>${escHtml(msgsLabel)}</td><td>${m.message_count}</td></tr>
  <tr><td>${escHtml(toolEventsLabel)}</td><td>${m.tool_event_count}</td></tr>
  <tr><td>${escHtml(branchLabel)}</td><td><code>${escHtml(m.branch || '—')}</code></td></tr>
  <tr><td>${escHtml(cwdLabel)}</td><td><code style="font-size:0.8rem">${escHtml(m.cwd || '—')}</code></td></tr>
  <tr><td>${escHtml(shaLabel)}</td><td><code style="font-size:0.75rem">${escHtml(m.raw_sha256.slice(0, 16))}…</code></td></tr>
</tbody>
</table>`
}

function renderSummaryCard(summary: string, t?: Translations): string {
  const label = t?.transcript.aiSummary ?? 'AI Summary'
  return `<div class="summary-card">
  <div class="summary-label">${escHtml(label)}</div>
  <div>${escHtml(summary)}</div>
</div>`
}

function renderBacklinks(backlinks: ManifestEntry[], t?: Translations): string {
  const heading = t?.transcript.referencedBy ?? 'Referenced By'
  const items = backlinks
    .map(m => {
      const url = transcriptHref(m)
      return `<li><a href="${escHtml(url)}">${escHtml(m.title || m.session_id)}</a></li>`
    })
    .join('')
  return `<div class="backlinks">
  <div class="backlinks-title">${escHtml(heading)} ${backlinks.length} session(s)</div>
  <ul>${items}</ul>
</div>`
}

function renderMessages(messages: RenderedMessage[], t?: Translations): string {
  const heading = t?.transcript.messages ?? 'Messages'
  const noMessages = t?.transcript.noMessages ?? 'No messages available for this session.'
  if (messages.length === 0) {
    return `<div class="card" style="color:var(--text-muted)">${escHtml(noMessages)}</div>`
  }

  const rendered = messages
    .map(msg => {
      const roleClass = msg.role === 'user' ? 'message-user' : 'message-assistant'
      const ts = msg.timestamp ? `<span style="margin-left:auto">${escHtml(msg.timestamp.slice(11, 19))}</span>` : ''
      const body = renderMessageBody(msg.text)
      return `<div class="message ${roleClass}">
  <div class="message-header">
    <span class="message-role">${escHtml(msg.role)}</span>${ts}
  </div>
  <div class="message-body">${body}</div>
</div>`
    })
    .join('\n')

  return `<h2 style="margin-top:1.5rem">${escHtml(heading)}</h2>
<div class="messages">${rendered}</div>`
}

/**
 * Render message text to HTML with code block support.
 * Input text is plain text from clean markdown.
 */
function renderMessageBody(text: string): string {
  // Process code blocks first (they contain preformatted content)
  const parts: string[] = []
  const codeBlockRe = /```[\w]*\n?([\s\S]*?)```/g
  let lastIndex = 0
  let match: RegExpExecArray | null

  while ((match = codeBlockRe.exec(text)) !== null) {
    if (match.index > lastIndex) {
      parts.push(renderInlineText(text.slice(lastIndex, match.index)))
    }
    const code = match[1] ?? ''
    parts.push(`<pre><code>${escHtml(code)}</code></pre>`)
    lastIndex = match.index + match[0].length
  }

  if (lastIndex < text.length) {
    parts.push(renderInlineText(text.slice(lastIndex)))
  }

  return parts.join('')
}

/** Render inline text (paragraphs + inline formatting). */
function renderInlineText(text: string): string {
  const paragraphs = text.split(/\n{2,}/).filter(p => p.trim())
  return paragraphs
    .map(p => `<p>${applyInlineMarkdown(escHtml(p.trim()))}</p>`)
    .join('')
}

/** Apply inline markdown to already-HTML-escaped text. */
function applyInlineMarkdown(html: string): string {
  return html
    .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.+?)\*/g, '<em>$1</em>')
    .replace(/`([^`]+)`/g, '<code>$1</code>')
    .replace(/\n/g, '<br>')
}

// ---------------------------------------------------------------------------
// Helper
// ---------------------------------------------------------------------------

function transcriptHref(m: ManifestEntry): string {
  return transcriptUrlFromTranscript(m)
}

/**
 * Session list page: tabular index of all imported transcripts, with client tab filtering.
 */

import type { ManifestEntry } from '@openmnemo/types'
import type { Translations } from '../i18n/types.js'
import { clientBadge, escHtml, htmlShell, renderNav, transcriptUrlFromRoot } from './layout.js'
import { renderTagBadges } from '../tags.js'

// ---------------------------------------------------------------------------
// Transcript list
// ---------------------------------------------------------------------------

export function renderTranscriptList(manifests: ManifestEntry[], t?: Translations, summaries?: Record<string, string>, tags?: Record<string, string[]>): string {
  const nav = renderNav('transcripts', 1, t)

  const sorted = [...manifests].sort((a, b) => b.started_at.localeCompare(a.started_at))

  const title = t?.sessions.title ?? 'Sessions'
  const clientLabel = t?.sessions.client ?? 'Client'
  const dateLabel = t?.sessions.date ?? 'Date'
  const idLabel = t?.sessions.id ?? 'ID'
  const msgsLabel = t?.sessions.msgs ?? 'Msgs'
  const toolsLabel = t?.sessions.tools ?? 'Tools'
  const allLabel = t?.sessions.all ?? 'All'

  if (sorted.length === 0) {
    const content = `<div class="page-header">
  <h1>${escHtml(title)}</h1>
  <p class="subtitle">${escHtml(t?.sessions.noSessions ?? 'No sessions imported yet.')}</p>
</div>`
    return htmlShell(title, content, nav)
  }

  // Collect unique clients
  const clientSet = new Set<string>()
  for (const m of sorted) clientSet.add(m.client)
  const clients = [...clientSet].sort()

  // Tab bar
  const tabBar = renderTabBar(allLabel, clients, sorted)

  const rows = sorted
    .map(m => {
      const url = transcriptHref(m)
      const date = m.started_at.slice(0, 10)
      const time = m.started_at.slice(11, 16)
      const badge = clientBadge(m.client)
      const summary = summaries?.[m.session_id] ?? ''
      const sessionTags = tags?.[m.session_id] ?? []
      const tagBadges = renderTagBadges(sessionTags)
      const meta = `${escHtml(m.client)} · ${escHtml(date)} · ${m.message_count} msgs`
      return `<tr data-client="${escHtml(m.client)}">
  <td>${badge}</td>
  <td><a href="${escHtml(url)}" data-summary="${escHtml(summary)}" data-meta="${escHtml(meta)}">${escHtml(m.title || m.session_id)}</a>${tagBadges}</td>
  <td style="color:var(--text-muted)">${escHtml(date)} ${escHtml(time)}</td>
  <td style="color:var(--text-muted);font-family:var(--font-mono);font-size:0.8rem">${escHtml(m.session_id.slice(0, 8))}</td>
  <td style="text-align:right;color:var(--text-muted)">${m.message_count}</td>
  <td style="text-align:right;color:var(--text-muted)">${m.tool_event_count}</td>
</tr>`
    })
    .join('')

  const filterJs = `<script>
(function() {
  document.addEventListener('DOMContentLoaded', function() {
    var tabs = document.querySelectorAll('.tab-btn');
    var rows = document.querySelectorAll('tr[data-client]');
    tabs.forEach(function(btn) {
      btn.addEventListener('click', function() {
        tabs.forEach(function(b) { b.classList.remove('active'); });
        btn.classList.add('active');
        var filter = btn.getAttribute('data-filter');
        rows.forEach(function(row) {
          if (!filter || row.getAttribute('data-client') === filter) {
            row.style.display = '';
          } else {
            row.style.display = 'none';
          }
        });
      });
    });
  });
})();
</script>`

  const content = `<div class="page-header">
  <h1>${escHtml(title)}</h1>
  <p class="subtitle">${sorted.length} session(s) imported</p>
</div>
${tabBar}
<div class="card" style="padding:0;overflow:hidden">
<table>
<thead><tr>
  <th>${escHtml(clientLabel)}</th>
  <th>Title</th>
  <th>${escHtml(dateLabel)}</th>
  <th>${escHtml(idLabel)}</th>
  <th style="text-align:right">${escHtml(msgsLabel)}</th>
  <th style="text-align:right">${escHtml(toolsLabel)}</th>
</tr></thead>
<tbody>${rows}</tbody>
</table>
</div>`

  return htmlShell(title, content, nav, filterJs)
}

// ---------------------------------------------------------------------------
// Tab bar
// ---------------------------------------------------------------------------

function renderTabBar(allLabel: string, clients: string[], manifests: ManifestEntry[]): string {
  const total = manifests.length
  const tabs = [
    `<button class="tab-btn active" data-filter="" type="button">${escHtml(allLabel)} (${total})</button>`,
    ...clients.map(client => {
      const count = manifests.filter(m => m.client === client).length
      return `<button class="tab-btn" data-filter="${escHtml(client)}" type="button">${escHtml(client)} (${count})</button>`
    }),
  ]
  return `<div class="tab-bar">${tabs.join('')}</div>`
}

// ---------------------------------------------------------------------------
// Helper
// ---------------------------------------------------------------------------

function transcriptHref(m: ManifestEntry): string {
  // From transcripts/index.html, the URL is relative to the transcripts/ dir
  // so we only need {client}/{stem}.html (no leading "transcripts/")
  return transcriptUrlFromRoot(m).replace(/^transcripts\//, '')
}
